// Debounce hook — prevents re-filtering on every keystroke
function useDebounce(value, delay) {
  var [dv, setDv] = useState(value);
  useEffect(
    function () {
      var t = setTimeout(function () {
        setDv(value);
      }, delay || 300);
      return function () {
        clearTimeout(t);
      };
    },
    [value]
  );
  return dv;
}

// ── usePersist: drop-in useState replacement that auto-saves to localStorage ──
// Usage: var [data, setData] = usePersist("kosmos_key", defaultValue);
function usePersist(key, defaultValue) {
  var [value, setValueRaw] = useState(function () {
    try {
      var stored = localStorage.getItem(key);
      if (stored !== null) return JSON.parse(stored);
    } catch (e) {
      /* corrupted storage — fall through to default */
    }
    return typeof defaultValue === 'function' ? defaultValue() : defaultValue;
  });

  var setValue = function (updater) {
    setValueRaw(function (prev) {
      var next = typeof updater === 'function' ? updater(prev) : updater;
      try {
        localStorage.setItem(key, JSON.stringify(next));
      } catch (e) {
        console.warn(
          "Kosmos: localStorage write failed for key '" + key + "':",
          e.message
        );
      }
      return next;
    });
  };

  return [value, setValue];
}

// Unique ID generator — timestamp-based, collision-safe
function genId(prefix) {
  return (
    (prefix || 'ID') +
    '-' +
    Date.now().toString(36).toUpperCase().slice(-5) +
    Math.floor(Math.random() * 100)
      .toString()
      .padStart(2, '0')
  );
}

// ── Toast notification system ──
var _toastPush = null;
function ToastContainer() {
  var [toasts, setToasts] = useState([]);
  useEffect(function () {
    _toastPush = function (msg, type) {
      var id = Date.now();
      setToasts(function (prev) {
        return prev.concat([{ id, msg, type: type || 'success' }]);
      });
      setTimeout(function () {
        setToasts(function (prev) {
          return prev.filter(function (t) {
            return t.id !== id;
          });
        });
      }, 3200);
    };
    return function () {
      _toastPush = null;
    };
  }, []);
  if (!toasts.length) return null;
  var BG = {
    success: '#16a34a',
    error: '#dc2626',
    warning: '#d97706',
    info: '#2563eb',
  };
  return (
    <div
      style={{
        position: 'fixed',
        bottom: 24,
        right: 24,
        zIndex: 9998,
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
        pointerEvents: 'none',
      }}
    >
      <style>{`@keyframes toastIn{from{opacity:0;transform:translateX(40px)}to{opacity:1;transform:translateX(0)}}`}</style>
      {toasts.map(function (t) {
        return (
          <div
            key={t.id}
            style={{
              background: BG[t.type] || BG.success,
              color: '#fff',
              padding: '11px 18px',
              borderRadius: 10,
              fontSize: 13,
              fontWeight: 600,
              boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
              maxWidth: 360,
              lineHeight: 1.45,
              animation: 'toastIn 0.25s ease',
              pointerEvents: 'auto',
            }}
          >
            {t.type === 'success' && '✓ '}
            {t.type === 'error' && '✗ '}
            {t.type === 'warning' && '⚠ '}
            {t.msg}
          </div>
        );
      })}
    </div>
  );
}
function toast(msg, type) {
  if (_toastPush) _toastPush(msg, type || 'success');
}

// ── Custom Confirm Dialog — replaces window.confirm ──
var _confirmShow = null;
function ConfirmDialog() {
  var [state, setState] = useState({
    open: false,
    message: '',
    subtext: '',
    confirmLabel: 'Delete',
    type: 'danger',
    onConfirm: null,
  });
  useEffect(function () {
    _confirmShow = function (message, onConfirm, opts) {
      setState({
        open: true,
        message,
        subtext: (opts && opts.subtext) || '',
        confirmLabel: (opts && opts.label) || 'Delete',
        type: (opts && opts.type) || 'danger',
        onConfirm,
      });
    };
    return function () {
      _confirmShow = null;
    };
  }, []);
  if (!state.open) return null;
  function doConfirm() {
    if (state.onConfirm) state.onConfirm();
    setState(function (s) {
      return Object.assign({}, s, { open: false, onConfirm: null });
    });
  }
  function doCancel() {
    setState(function (s) {
      return Object.assign({}, s, { open: false, onConfirm: null });
    });
  }
  var isDanger = state.type === 'danger';
  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(0,0,0,0.5)',
        zIndex: 9997,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 20,
      }}
    >
      <div
        style={{
          background: '#fff',
          borderRadius: 14,
          padding: '32px 32px 24px',
          maxWidth: 420,
          width: '100%',
          boxShadow: '0 20px 60px rgba(0,0,0,0.25)',
          textAlign: 'center',
        }}
      >
        <div
          style={{
            width: 54,
            height: 54,
            borderRadius: '50%',
            background: isDanger ? '#fee2e2' : '#fef3c7',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            margin: '0 auto 16px',
          }}
        >
          <AlertTriangle size={26} color={isDanger ? '#dc2626' : '#d97706'} />
        </div>
        <div
          style={{
            fontSize: 16,
            fontWeight: 800,
            color: '#111827',
            marginBottom: 6,
          }}
        >
          Are you sure?
        </div>
        <div
          style={{
            fontSize: 13,
            color: '#6b7280',
            lineHeight: 1.6,
            marginBottom: state.subtext ? 8 : 24,
          }}
        >
          {state.message}
        </div>
        {state.subtext && (
          <div style={{ fontSize: 11, color: '#9ca3af', marginBottom: 24 }}>
            {state.subtext}
          </div>
        )}
        <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
          <button
            onClick={doCancel}
            style={{
              padding: '9px 26px',
              borderRadius: 8,
              border: '1px solid #e5e9f0',
              background: '#fff',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              color: '#374151',
            }}
          >
            Cancel
          </button>
          <button
            onClick={doConfirm}
            style={{
              padding: '9px 26px',
              borderRadius: 8,
              border: 'none',
              background: isDanger ? '#dc2626' : '#4f46e5',
              color: '#fff',
              fontSize: 13,
              fontWeight: 700,
              cursor: 'pointer',
            }}
          >
            {state.confirmLabel}
          </button>
        </div>
      </div>
    </div>
  );
}
function showConfirm(message, onConfirm, opts) {
  if (_confirmShow) {
    _confirmShow(message, onConfirm, opts);
  } else {
    if (window.confirm(message)) onConfirm();
  }
}

// ── Pagination component ──
var PAGE_SIZES = [25, 50, 100, 250];
function Pagination({ total, page, perPage, onPage, onPerPage }) {
  var totalPages = Math.max(1, Math.ceil(total / perPage));
  if (total === 0) return null;
  var start = Math.min((page - 1) * perPage + 1, total);
  var end = Math.min(page * perPage, total);
  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '10px 16px',
        borderTop: '1px solid #e5e9f0',
        background: '#fafbfe',
        flexWrap: 'wrap',
        gap: 8,
        flexShrink: 0,
      }}
    >
      <div style={{ fontSize: 12, color: '#6b7280' }}>
        Showing{' '}
        <strong style={{ color: '#374151' }}>
          {start}–{end}
        </strong>{' '}
        of{' '}
        <strong style={{ color: '#374151' }}>{total.toLocaleString()}</strong>{' '}
        records
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
        {onPerPage && (
          <select
            value={perPage}
            onChange={function (e) {
              onPerPage(parseInt(e.target.value));
              onPage(1);
            }}
            style={{
              border: '1px solid #e5e9f0',
              borderRadius: 6,
              padding: '4px 8px',
              fontSize: 12,
              outline: 'none',
              background: '#fff',
              color: '#374151',
            }}
          >
            {PAGE_SIZES.map(function (s) {
              return (
                <option key={s} value={s}>
                  {s} / page
                </option>
              );
            })}
          </select>
        )}
        <button
          disabled={page <= 1}
          onClick={function () {
            onPage(page - 1);
          }}
          style={{
            background: page > 1 ? '#fff' : '#f3f4f6',
            border: '1px solid #e5e9f0',
            borderRadius: 6,
            padding: '5px 11px',
            cursor: page > 1 ? 'pointer' : 'not-allowed',
            fontSize: 12,
            color: page > 1 ? '#374151' : '#d1d5db',
            fontWeight: 600,
          }}
        >
          ‹
        </button>
        <span
          style={{
            fontSize: 12,
            color: '#374151',
            fontWeight: 600,
            minWidth: 90,
            textAlign: 'center',
          }}
        >
          Page {page} / {totalPages}
        </span>
        <button
          disabled={page >= totalPages}
          onClick={function () {
            onPage(page + 1);
          }}
          style={{
            background: page < totalPages ? '#fff' : '#f3f4f6',
            border: '1px solid #e5e9f0',
            borderRadius: 6,
            padding: '5px 11px',
            cursor: page < totalPages ? 'pointer' : 'not-allowed',
            fontSize: 12,
            color: page < totalPages ? '#374151' : '#d1d5db',
            fontWeight: 600,
          }}
        >
          ›
        </button>
      </div>
    </div>
  );
}

